import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { OrderRepository } from '../../src/repositories/order.repository.js';
import { AnalyticsService } from '../../src/services/analytics.service.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';
import type { AnalyticsQuery } from '../../src/models/analytics.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function makeUser(overrides: Partial<User> & { id: string }): User {
  return {
    name: 'Test User',
    email: `${overrides.id}@example.com`,
    role: 'member',
    createdAt: new Date('2025-01-15'),
    updatedAt: new Date('2025-01-15'),
    ...overrides,
  };
}

function makeOrder(overrides: Partial<Order> & { id: string; userId: string }): Order {
  return {
    items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 100 }],
    total: 100,
    status: 'pending',
    createdAt: new Date('2025-02-01'),
    updatedAt: new Date('2025-02-01'),
    ...overrides,
  };
}

describe('AnalyticsService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let orderRepo: OrderRepository;
  let service: AnalyticsService;

  // Standard query covering February 2025
  const febQuery: AnalyticsQuery = {
    startDate: new Date('2025-02-01'),
    endDate: new Date('2025-02-28T23:59:59.999Z'),
    granularity: 'day',
  };

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    orderRepo = new OrderRepository(db);
    service = new AnalyticsService(orderRepo, userRepo);
  });

  // -------------------------------------------------------------------------
  // getMetricSummary
  // -------------------------------------------------------------------------

  describe('getMetricSummary', () => {
    it('should return zero values when no data exists', async () => {
      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.metricType).toBe('orders');
      expect(result.currentValue).toBe(0);
      expect(result.previousValue).toBe(0);
      expect(result.changePercent).toBe(0);
      expect(result.trend).toBe('flat');
      expect(result.timeSeries).toBeDefined();
    });

    it('should count orders in range', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', createdAt: new Date('2025-02-10') }));
      // Out-of-range order
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u1', createdAt: new Date('2025-03-05') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.currentValue).toBe(2);
    });

    it('should sum revenue in range', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 50.5, createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 30.25, createdAt: new Date('2025-02-10') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'revenue',
      });

      expect(result.currentValue).toBe(80.75);
    });

    it('should count users created in range', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-02-05') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-02-20') }));
      // Out of range
      userRepo.save(makeUser({ id: 'u3', createdAt: new Date('2025-01-01') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'users',
      });

      expect(result.currentValue).toBe(2);
    });

    it('should compute average order value', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200, createdAt: new Date('2025-02-10') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'average-order-value',
      });

      expect(result.currentValue).toBe(150);
    });

    it('should return zero AOV when no orders exist', async () => {
      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'average-order-value',
      });

      expect(result.currentValue).toBe(0);
    });

    it('should compute change percent compared to previous period', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      // Previous period: January
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-01-10') }));
      // Current period: February — two orders
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u1', createdAt: new Date('2025-02-15') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.currentValue).toBe(2);
      expect(result.previousValue).toBe(1);
      expect(result.changePercent).toBe(100);
      expect(result.trend).toBe('up');
    });

    it('should show downward trend when current < previous', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      // Previous period: two orders in January
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-01-10') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', createdAt: new Date('2025-01-20') }));
      // Current period: one order in February
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u1', createdAt: new Date('2025-02-05') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.currentValue).toBe(1);
      expect(result.previousValue).toBe(2);
      expect(result.changePercent).toBe(-50);
      expect(result.trend).toBe('down');
    });

    it('should show 100% change when previous is zero and current is positive', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-05') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.previousValue).toBe(0);
      expect(result.changePercent).toBe(100);
      expect(result.trend).toBe('up');
    });

    it('should include timeSeries data', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-01T12:00:00Z') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.timeSeries.length).toBeGreaterThan(0);
      // At least one bucket should have value 1
      const nonZero = result.timeSeries.filter((p) => p.value > 0);
      expect(nonZero.length).toBe(1);
      expect(nonZero[0].value).toBe(1);
    });

    it('should default granularity to day', async () => {
      const result = await service.getMetricSummary({
        startDate: new Date('2025-02-01'),
        endDate: new Date('2025-02-03T23:59:59.999Z'),
        metricType: 'orders',
      });

      // Should have time series with day-level buckets
      expect(result.timeSeries.length).toBeGreaterThanOrEqual(3);
    });
  });

  // -------------------------------------------------------------------------
  // getOrderStatusBreakdown
  // -------------------------------------------------------------------------

  describe('getOrderStatusBreakdown', () => {
    it('should return all statuses with zero counts when no orders exist', async () => {
      const result = await service.getOrderStatusBreakdown(febQuery);

      expect(result).toHaveLength(5);
      for (const entry of result) {
        expect(entry.count).toBe(0);
        expect(entry.percentage).toBe(0);
      }
    });

    it('should calculate counts and percentages', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', status: 'pending', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', status: 'pending', createdAt: new Date('2025-02-06') }));
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u1', status: 'confirmed', createdAt: new Date('2025-02-07') }));
      orderRepo.save(makeOrder({ id: 'o4', userId: 'u1', status: 'delivered', createdAt: new Date('2025-02-08') }));

      const result = await service.getOrderStatusBreakdown(febQuery);

      const pending = result.find((r) => r.status === 'pending')!;
      expect(pending.count).toBe(2);
      expect(pending.percentage).toBe(50);

      const confirmed = result.find((r) => r.status === 'confirmed')!;
      expect(confirmed.count).toBe(1);
      expect(confirmed.percentage).toBe(25);

      const delivered = result.find((r) => r.status === 'delivered')!;
      expect(delivered.count).toBe(1);
      expect(delivered.percentage).toBe(25);

      const shipped = result.find((r) => r.status === 'shipped')!;
      expect(shipped.count).toBe(0);
      expect(shipped.percentage).toBe(0);
    });

    it('should only include orders within the date range', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', createdAt: new Date('2025-03-05') }));

      const result = await service.getOrderStatusBreakdown(febQuery);

      const total = result.reduce((sum, r) => sum + r.count, 0);
      expect(total).toBe(1);
    });
  });

  // -------------------------------------------------------------------------
  // getRevenueBreakdown
  // -------------------------------------------------------------------------

  describe('getRevenueBreakdown', () => {
    it('should return zeros when no orders exist', async () => {
      const result = await service.getRevenueBreakdown(febQuery);

      expect(result.totalRevenue).toBe(0);
      expect(result.averageOrderValue).toBe(0);
      expect(result.byStatus).toHaveLength(5);
      for (const entry of result.byStatus) {
        expect(entry.revenue).toBe(0);
      }
    });

    it('should compute total revenue and average', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200, createdAt: new Date('2025-02-10') }));
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u1', total: 300, createdAt: new Date('2025-02-15') }));

      const result = await service.getRevenueBreakdown(febQuery);

      expect(result.totalRevenue).toBe(600);
      expect(result.averageOrderValue).toBe(200);
    });

    it('should break down revenue by status', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, status: 'pending', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 250, status: 'delivered', createdAt: new Date('2025-02-10') }));

      const result = await service.getRevenueBreakdown(febQuery);

      const pending = result.byStatus.find((r) => r.status === 'pending')!;
      expect(pending.revenue).toBe(100);

      const delivered = result.byStatus.find((r) => r.status === 'delivered')!;
      expect(delivered.revenue).toBe(250);
    });

    it('should round revenue to two decimal places', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 10.333, createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 10.333, createdAt: new Date('2025-02-06') }));
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u1', total: 10.334, createdAt: new Date('2025-02-07') }));

      const result = await service.getRevenueBreakdown(febQuery);

      expect(result.totalRevenue).toBe(31);
      // 31/3 = 10.333... -> rounded to 10.33
      expect(result.averageOrderValue).toBe(10.33);
    });
  });

  // -------------------------------------------------------------------------
  // getUserAnalytics
  // -------------------------------------------------------------------------

  describe('getUserAnalytics', () => {
    it('should return zeros when no users exist', async () => {
      const result = await service.getUserAnalytics(febQuery);

      expect(result.totalUsers).toBe(0);
      expect(result.newUsersInPeriod).toBe(0);
      expect(result.activeUsersInPeriod).toBe(0);
      expect(result.byRole).toHaveLength(0);
    });

    it('should count total users (all time, not just in range)', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-01-01') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-02-10') }));

      const result = await service.getUserAnalytics(febQuery);

      expect(result.totalUsers).toBe(2);
    });

    it('should count new users in range only', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2024-01-01') }));
      userRepo.save(makeUser({ id: 'u2', createdAt: new Date('2025-02-10') }));
      userRepo.save(makeUser({ id: 'u3', createdAt: new Date('2025-02-20') }));

      const result = await service.getUserAnalytics(febQuery);

      expect(result.newUsersInPeriod).toBe(2);
    });

    it('should count active users (users with orders in range)', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      userRepo.save(makeUser({ id: 'u2' }));
      userRepo.save(makeUser({ id: 'u3' }));
      // u1 and u2 have orders in range, u3 does not
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', createdAt: new Date('2025-02-06') }));
      orderRepo.save(makeOrder({ id: 'o3', userId: 'u2', createdAt: new Date('2025-02-07') }));

      const result = await service.getUserAnalytics(febQuery);

      expect(result.activeUsersInPeriod).toBe(2);
    });

    it('should provide role breakdown for all users', async () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin' }));
      userRepo.save(makeUser({ id: 'u2', role: 'member' }));
      userRepo.save(makeUser({ id: 'u3', role: 'member' }));
      userRepo.save(makeUser({ id: 'u4', role: 'viewer' }));

      const result = await service.getUserAnalytics(febQuery);

      const admin = result.byRole.find((r) => r.role === 'admin');
      expect(admin?.count).toBe(1);

      const member = result.byRole.find((r) => r.role === 'member');
      expect(member?.count).toBe(2);

      const viewer = result.byRole.find((r) => r.role === 'viewer');
      expect(viewer?.count).toBe(1);
    });
  });

  // -------------------------------------------------------------------------
  // getDashboard
  // -------------------------------------------------------------------------

  describe('getDashboard', () => {
    it('should return complete dashboard data with empty database', async () => {
      const result = await service.getDashboard(febQuery);

      expect(result.query).toBeDefined();
      expect(result.metrics.orders.currentValue).toBe(0);
      expect(result.metrics.revenue.currentValue).toBe(0);
      expect(result.metrics.users.currentValue).toBe(0);
      expect(result.metrics.averageOrderValue.currentValue).toBe(0);
      expect(result.orderStatusBreakdown).toHaveLength(5);
      expect(result.revenueBreakdown.totalRevenue).toBe(0);
      expect(result.userAnalytics.totalUsers).toBe(0);
      expect(result.generatedAt).toBeInstanceOf(Date);
    });

    it('should return populated dashboard with data', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-02-01') }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 100, createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 200, status: 'delivered', createdAt: new Date('2025-02-10') }));

      const result = await service.getDashboard(febQuery);

      expect(result.metrics.orders.currentValue).toBe(2);
      expect(result.metrics.revenue.currentValue).toBe(300);
      expect(result.metrics.users.currentValue).toBe(1);
      expect(result.metrics.averageOrderValue.currentValue).toBe(150);
      expect(result.revenueBreakdown.totalRevenue).toBe(300);
      expect(result.userAnalytics.activeUsersInPeriod).toBe(1);
    });

    it('should default granularity to day', async () => {
      const result = await service.getDashboard({
        startDate: new Date('2025-02-01'),
        endDate: new Date('2025-02-28T23:59:59.999Z'),
      });

      expect(result.query.granularity).toBe('day');
    });

    it('should respect provided granularity', async () => {
      const result = await service.getDashboard({
        ...febQuery,
        granularity: 'week',
      });

      expect(result.query.granularity).toBe('week');
    });
  });

  // -------------------------------------------------------------------------
  // Edge cases
  // -------------------------------------------------------------------------

  describe('edge cases', () => {
    it('should handle a single data point', async () => {
      userRepo.save(makeUser({ id: 'u1', createdAt: new Date('2025-02-15') }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 42, createdAt: new Date('2025-02-15') }));

      const result = await service.getDashboard(febQuery);

      expect(result.metrics.orders.currentValue).toBe(1);
      expect(result.metrics.revenue.currentValue).toBe(42);
      expect(result.metrics.averageOrderValue.currentValue).toBe(42);
    });

    it('should handle orders at exact range boundaries', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-01') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', createdAt: new Date('2025-02-28T23:59:59.999Z') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.currentValue).toBe(2);
    });

    it('should handle many orders', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      for (let i = 0; i < 100; i++) {
        const day = (i % 28) + 1;
        const dayStr = day.toString().padStart(2, '0');
        orderRepo.save(
          makeOrder({
            id: `o${i}`,
            userId: 'u1',
            total: 10 + i,
            createdAt: new Date(`2025-02-${dayStr}T12:00:00Z`),
          }),
        );
      }

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
      });

      expect(result.currentValue).toBe(100);
    });

    it('should handle fractional currency values', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', total: 0.1, createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u1', total: 0.2, createdAt: new Date('2025-02-06') }));

      const result = await service.getMetricSummary({
        ...febQuery,
        metricType: 'revenue',
      });

      // 0.1 + 0.2 = 0.30000000000000004 in JS, should be rounded to 0.3
      expect(result.currentValue).toBe(0.3);
    });

    it('should handle different time granularities', async () => {
      userRepo.save(makeUser({ id: 'u1' }));
      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-05') }));

      const hourly = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
        granularity: 'hour',
      });
      expect(hourly.timeSeries.length).toBeGreaterThan(28); // more than day buckets

      const monthly = await service.getMetricSummary({
        ...febQuery,
        metricType: 'orders',
        granularity: 'month',
      });
      expect(monthly.timeSeries.length).toBeLessThanOrEqual(2); // 1-2 month buckets
    });

    it('should handle multiple users with different roles for analytics', async () => {
      userRepo.save(makeUser({ id: 'u1', role: 'admin', createdAt: new Date('2025-02-01') }));
      userRepo.save(makeUser({ id: 'u2', role: 'member', createdAt: new Date('2025-02-02') }));
      userRepo.save(makeUser({ id: 'u3', role: 'viewer', createdAt: new Date('2025-02-03') }));

      orderRepo.save(makeOrder({ id: 'o1', userId: 'u1', createdAt: new Date('2025-02-05') }));
      orderRepo.save(makeOrder({ id: 'o2', userId: 'u2', createdAt: new Date('2025-02-06') }));

      const result = await service.getUserAnalytics(febQuery);

      expect(result.totalUsers).toBe(3);
      expect(result.newUsersInPeriod).toBe(3);
      expect(result.activeUsersInPeriod).toBe(2);
      expect(result.byRole).toHaveLength(3);
    });
  });
});

